      "content": "const { v4: uuidv4 } = require('uuid');
const projects = [];

function createProject(name) {
  const project = { id: uuidv4(), name, members: [] };
  projects.push(project);
  return project;
}

function getProject(id) {
  return projects.find(project => project.id === id);
}

module.exports = {
  createProject,
  getProject,
};
