      "path": "src/modules/tasks/service.js",
      "content": "const projects = require('../projects/service');

function createTask(projectId, title) {
  const project = projects.getProject(projectId);
  const task = { id: uuidv4(), projectId, title, status: 'todo' };
  project.tasks.push(task);
  return task;
}

function updateTaskStatus(taskId, newStatus) {
  if (newStatus !== 'todo' && newStatus !== 'done') return null;
  const task = getTaskById(taskId);
  if (!task) return null;
  task.status = newStatus;
  return { task };
}

function getTasksByStatus(projectId, status) {
  const project = projects.getProject(projectId);
  return project.tasks.filter(task => task.status === status);
}

function getTaskById(taskId) {
  for (const project of projects) {
    const task = project.tasks.find(task => task.id === taskId);
    if (task) return task;
  }
  return null;
}

module.exports = {
  createTask,
  updateTaskStatus,
  getTasksByStatus,
};
